import fs from "node:fs";
import path from "node:path";
import type { RunHistory } from "./types.js";

const RUNS_DIR = path.join(process.cwd(), "data", "runs");

function ensureDir() {
  if (!fs.existsSync(RUNS_DIR)) {
    fs.mkdirSync(RUNS_DIR, { recursive: true });
  }
}

function assertSafeId(id: string): void {
  if (!/^[\w-]+$/.test(id)) {
    throw new Error(`Invalid run id: ${id}`);
  }
}

function filePath(id: string): string {
  assertSafeId(id);
  ensureDir();

  for (const entry of fs.readdirSync(RUNS_DIR)) {
    if (!entry.endsWith(".json")) {
      continue;
    }

    const candidatePath = path.join(RUNS_DIR, entry);

    try {
      const run = JSON.parse(fs.readFileSync(candidatePath, "utf-8")) as RunHistory;
      if (run.id === id) {
        return candidatePath;
      }
    } catch {
      continue;
    }
  }

  return path.join(RUNS_DIR, `${Date.now()}-${id}.json`);
}

export function listRunHistories(scenarioId?: string): RunHistory[] {
  ensureDir();

  const runs = fs
    .readdirSync(RUNS_DIR)
    .filter((entry) => entry.endsWith(".json"))
    .map((entry) => {
      try {
        return JSON.parse(
          fs.readFileSync(path.join(RUNS_DIR, entry), "utf-8")
        ) as RunHistory;
      } catch {
        return null;
      }
    })
    .filter((run): run is RunHistory => run !== null);

  if (scenarioId !== undefined) {
    return runs.filter((run) => run.scenarioId === scenarioId);
  }

  return runs;
}

export function getRunHistory(id: string): RunHistory | null {
  assertSafeId(id);
  ensureDir();

  for (const entry of fs.readdirSync(RUNS_DIR)) {
    if (!entry.endsWith(".json")) {
      continue;
    }

    const candidatePath = path.join(RUNS_DIR, entry);

    try {
      const run = JSON.parse(fs.readFileSync(candidatePath, "utf-8")) as RunHistory;
      if (run.id === id) {
        return run;
      }
    } catch {
      continue;
    }
  }

  return null;
}

export function saveRunHistory(run: RunHistory): void {
  assertSafeId(run.id);
  ensureDir();

  const existing = getRunHistory(run.id);
  let targetPath: string;

  if (existing !== null) {
    targetPath = filePath(run.id);
  } else {
    targetPath = path.join(RUNS_DIR, `${Date.now()}-${run.id}.json`);
  }

  fs.writeFileSync(targetPath, JSON.stringify(run, null, 2), "utf-8");
}

export function deleteRunHistory(id: string): boolean {
  assertSafeId(id);
  ensureDir();

  for (const entry of fs.readdirSync(RUNS_DIR)) {
    if (!entry.endsWith(".json")) {
      continue;
    }

    const candidatePath = path.join(RUNS_DIR, entry);

    try {
      const run = JSON.parse(fs.readFileSync(candidatePath, "utf-8")) as RunHistory;
      if (run.id === id) {
        fs.unlinkSync(candidatePath);
        return true;
      }
    } catch {
      continue;
    }
  }

  return false;
}

export function setGolden(id: string, isGolden: boolean): boolean {
  assertSafeId(id);
  ensureDir();

  const target = getRunHistory(id);
  if (target === null) {
    return false;
  }

  if (isGolden) {
    // 같은 scenarioId의 기존 골든 셋 해제
    for (const entry of fs.readdirSync(RUNS_DIR)) {
      if (!entry.endsWith(".json")) {
        continue;
      }

      const candidatePath = path.join(RUNS_DIR, entry);

      try {
        const run = JSON.parse(fs.readFileSync(candidatePath, "utf-8")) as RunHistory;
        if (run.scenarioId === target.scenarioId && run.isGolden && run.id !== id) {
          run.isGolden = false;
          fs.writeFileSync(candidatePath, JSON.stringify(run, null, 2), "utf-8");
        }
      } catch {
        continue;
      }
    }
  }

  // 대상 run의 isGolden 갱신
  target.isGolden = isGolden;
  fs.writeFileSync(filePath(id), JSON.stringify(target, null, 2), "utf-8");

  return true;
}

